import java.io.File;
import java.io.IOException;
import java.nio.file.Files;
import java.nio.file.Paths;

public class PathTraversalSecure {

    private static final String basePath = "/var/www/data/";

    public static void main(String[] args) {
        String userInput = "../etc/passwd"; // User input with malicious path traversal

        // Check if userInput contains any illegal characters
        if (!userInput.contains("..") && !userInput.contains("~")) {
            String filePath = basePath + userInput;

            File file = new File(filePath);

            if (file.exists() && file.getAbsolutePath().startsWith(basePath)) {
                try {
                    byte[] fileData = Files.readAllBytes(Paths.get(filePath));
                    System.out.println(new String(fileData));
                } catch (IOException e) {
                    e.printStackTrace();
                }
            } else {
                System.out.println("File not found or unauthorized access.");
            }
        } else {
            System.out.println("Invalid input.");
        }
    }
}

